export function getCourseBySlugAr(slug: string): Course | undefined {
  return COURSES_AR.find((c) => c.slug === slug)
}

export function getLessonBySlugAr(courseSlug: string, lessonSlug: string) {
  const course = getCourseBySlugAr(courseSlug)
  if (!course) return undefined
  const index = course.lessons.findIndex((l) => l.slug === lessonSlug)
  if (index === -1) return undefined
  return { course, lesson: course.lessons[index], index }
}
